member.example:
Bind the Transform position using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformPositionBinder _position;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _position;
    }


Bind the Transform position by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Transform _target;
        
        private TransformPositionBinder Position =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Vector3 _position;
    }

Switch the Transform position between two values using a serialized binder field — the target Transform is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TransformPositionSwitcherBinder _isVisible;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }


Switch the Transform position between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Transform _target;
        
        [SerializeField]
        private Vector3 _visiblePosition;
        
        [SerializeField]
        private Vector3 _hiddenPosition;
        
        private TransformPositionSwitcherBinder IsVisible => new(
            _target, _visiblePosition, _hiddenPosition);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isVisible;
    }
